function [imgOut,cnt] = f1DXrayOutV02(img,prm,ornt,flp)%% low pass filter, 1D%% [img,cntX] = f1DXrayOutV01(img,prm,ornt)%% img:      input image% prm:      1x4 array, [fct,pit,minX,itr]% fct:      factor to take out the point% pit:      depth of the pit% minX:     minimun counts to be taken% itr:      number of iteration% ornt:     orientation, 0 for horizontal reference, 1 for vertical ref% flp:      =1 for flipping to dip removal%% imgOut:      input image% cnt:     counts that taken out from image% Kei Nakamura% Created on Monday, February 21st 2011.% Modified on%% ver.1: created%% input and initializationif ornt == 1;   % if ornt == 1, flip.    img = img'; % treat as horizontal filterendif flp ==1; % flip it    maxV = max(max(img));    minV = min(min(img));    img = -img + maxV + minV;end% figure(10)% pcolor(img(:,500:530))% shading interp% colorbarfct = prm(1);pit = prm(2);minX = prm(3);itr = prm(4);cnt = sum(sum(img));%% make padded imageedgT = img(1:pit,:);                % edge top for virtual imageedgB = img(end-pit+1:end,:);        % edge for bottomedgL = img(:,1:pit);                % edge leftedgR = img(:,end-pit+1:end);        % edge rightcrn = zeros(pit,pit);               % cornerpdImg = [crn,edgT,crn;edgL,img,edgR;crn,edgB,crn];    % image+pad%% allocation[szy,szx] = size(img);imgOut = img;   % copyimgRfL = zeros(szy,szx); imgRfR = zeros(szy,szx);imgRf = zeros(szy,szx); imgX = zeros(szy,szx);%% main loopfor sss=1:itr        %% make averaged image    imgRfL(:,:) = 0.5*pdImg(1+pit:end-pit,1:end-2*pit);    % left reference/4    imgRfR(:,:) = 0.5*pdImg(1+pit:end-pit,1+2*pit:end);    % right reference/4    imgRf(:,:) = imgRfL + imgRfR;       % averaged reference        %% replace to average if logic is on    imgX(:,:) = imgOut - fct*imgRf;                   % factored subtraction        imgX(:,:) = imgX>0&img>=minX;                        % logic for pixels to be replaced    imgOut(:,:) = imgOut.*(~imgX)+imgRf.*imgX;           %     %% update padded image    edgT(:,:) = imgOut(1:pit,:);                % edge top for virtual image    edgB(:,:) = imgOut(end-pit+1:end,:);        % edge for bottom    edgL(:,:) = imgOut(:,1:pit);                % edge left    edgR(:,:) = imgOut(:,end-pit+1:end);        % edge right    pdImg(:,:) = [crn,edgT,crn;edgL,imgOut,edgR;crn,edgB,crn];    % update padded image       endcnt = cnt - sum(sum(imgOut));if ornt == 1;   % if ornt == 1, flip.    imgOut = imgOut'; % treat as horizontal filterendif flp ==1; % flip it    maxV = max(max(imgOut));    minV = min(min(imgOut));    imgOut = -imgOut + maxV + minV;end
